import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import { siteImages } from "../utils/siteImages";
import project4 from "../assets/images/projects/home.png";

function Projects() {
  const [projects, setProjects] = useState([]);

  const stats = [
    { value: "12+", label: "Projects Completed" },
    { value: "5+", label: "Clients Served" },
    { value: "Full Stack", label: "Frontend + Backend Delivery" },
    { value: "Modern UI", label: "Scalable Product Experience" },
  ];

  const handleImageError = (e) => {
    e.currentTarget.src = siteImages.fallback;
  };

  // ✅ API CALL
  useEffect(() => {
    axios
      .get(`${process.env.REACT_APP_API_URL}/projects`)
      .then((res) => setProjects(res.data))
      .catch((err) => console.log(err));
  }, []);

  return (
    <section className="min-h-screen overflow-hidden bg-slate-50 text-slate-900">
      <div className="mx-auto max-w-7xl px-6 py-16 sm:px-8 lg:px-10 lg:py-20">

        {/* HERO SAME */}
        <div className="relative overflow-hidden rounded-[36px] border border-slate-200 bg-white shadow-[0_25px_80px_rgba(15,23,42,0.08)]">
          <div className="relative px-6 py-12 sm:px-10 lg:px-14 lg:py-16">
            <h1 className="text-4xl font-bold">Our Projects</h1>
          </div>
        </div>

        {/* ✅ Featured Project */}
        {projects.length > 0 && (
          <div className="mt-14 grid gap-8 lg:grid-cols-2">
            <div className="p-8 bg-white rounded-2xl">
              <h2 className="text-3xl font-bold">
                {projects[0].title}
              </h2>
              <p className="mt-4">{projects[0].description}</p>

              <Link
                to={`/projects/${projects[0]._id}`}
                className="mt-6 inline-block bg-black text-white px-5 py-2 rounded"
              >
                View Project
              </Link>
            </div>

            <img
              src={project4}
              alt=""
              className="rounded-xl"
            />
          </div>
        )}

        {/* ✅ Project Grid */}
        <div className="grid gap-6 md:grid-cols-2 xl:grid-cols-3 mt-10">
          {projects.map((project, index) => {
            const isOngoing = index >= projects.length - 3;

            const CardWrapper = isOngoing ? "div" : Link;

            return (
              <CardWrapper
                key={project._id}
                {...(!isOngoing && { to: `/projects/${project._id}` })}
                className="border p-4 rounded-xl bg-white"
              >
                <img
                  src={project.image}
                  alt={project.title}
                  onError={handleImageError}
                  className="h-60 w-full object-cover rounded"
                />

                <h3 className="mt-4 text-xl font-semibold">
                  {project.title}
                </h3>

                <p className="text-sm text-gray-600 mt-2">
                  {project.description}
                </p>

                {!isOngoing && (
                  <p className="mt-3 text-blue-600">
                    View Project →
                  </p>
                )}

                {isOngoing && (
                  <p className="mt-3 text-orange-500">
                    Ongoing
                  </p>
                )}
              </CardWrapper>
            );
          })}
        </div>
      </div>
    </section>
  );
}

export default Projects;
